from outlines.prompts import prompt, register_filter, unregister_filter

register_filter('shout', lambda s: s.upper())

@prompt
def greet(name):
    '''Hello {{ name | shout }}!'''

print(greet('world'))

unregister_filter('shout')

@prompt
def greet2(name):
    '''Hello {{ name | shout }}!'''

try:
    greet2('world')
    print('ERROR: should have raised')
except Exception as e:
    print('OK, raised after unregister for new templates:', type(e).__name__)

# local/builtin filter precedence: registering a filter named 'name' should not override the builtin
register_filter('name', lambda x: 'overridden')

@prompt
def uses_name_filter(fn):
    '''{{ fn | name }}'''

def sample_fn(): pass
print(uses_name_filter(sample_fn))
